33		async exchangeCode({
34			code,
35		}: {
36			code: string;
37		}): Promise<IAtlassianTokenResponse> {
38			const { data } = await this.httpService.axiosRef.post<IAtlassianTokenResponse>(
39				ATLASSIAN_TOKEN_URL,
40				{
41					grant_type: 'authorization_code',
42					client_id: this.configService.get<string>({ key: JIRA_CLIENT_ID }),
43					client_secret: this.configService.get<string>({ key: JIRA_CLIENT_SECRET }),
44					redirect_uri: this.configService.get<string>({ key: JIRA_CALLBACK_URL }),
45					code,
46				},
47			);
48			return data;
49		}
50	
51		async getAccessibleResources({
52			accessToken,
53		}: {
54			accessToken: string;
55		}): Promise<IAtlassianResource[]> {
56			const { data } = await this.httpService.axiosRef.get<IAtlassianResource[]>(
57				ATLASSIAN_RESOURCES_URL,
58				{ headers: { Authorization: `Bearer ${accessToken}` } },
59			);
60			return data;
61		}
62	
63		async getValidToken({
64			installation,
65		}: {
66			installation: IJiraInstallationBase;
67		}): Promise<string> {
68			const expiresAt = new Date(installation.token_expires_at).getTime();
69			const now = Date.now();
70	
71			if (expiresAt - now > TOKEN_REFRESH_BUFFER_MS) {
72				return installation.access_token;
73			}
74	
75			try {
76				const refreshed = await this.refreshToken({
77					refreshToken: installation.refresh_token,
78				});
79	
80				const tokenExpiresAt = new Date(Date.now() + refreshed.expires_in * 1000);
81	
82				await this.installationModel.updateTokens({
83					id: installation._id,
84					accessToken: refreshed.access_token,
85					refreshToken: refreshed.refresh_token,
86					tokenExpiresAt,
87				});
88	
89				this.logger.debug(`Refreshed token for installation ${installation._id}`);
90				return refreshed.access_token;
91			} catch (error) {
92				await this.installationModel.markNeedsReauth({ id: installation._id });
93				this.logger.error(
94					`Token refresh failed for installation ${installation._id}: ${(error as Error).message}`,
95				);
96				throw error;
97			}
98		}
