100		async listProjects({
101			cloudId,
102			token,
103		}: {
104			cloudId: string;
105			token: string;
106		}): Promise<IJiraApiProject[]> {
107			const base = this.apiBase({ cloudId });
108			const projects: IJiraApiProject[] = [];
109			let startAt = 0;
110			const maxResults = 50;
111	
112			while (true) {
113				const { data } = await this.httpService.axiosRef.get<{
114					values: IJiraApiProject[];
115					isLast: boolean;
116				}>(`${base}/project/search`, {
117					headers: { Authorization: `Bearer ${token}` },
118					params: { startAt, maxResults, typeKey: 'software' },
119				});
120	
121				projects.push(...data.values);
122				if (data.isLast || data.values.length === 0) break;
123				startAt += maxResults;
124			}
125	
126			return projects;
127		}
