1443		while (true) {
1444			const { data: commits } = await this.httpService.axiosRef.get<IGithubApiCommit[]>(
1445				`https://api.github.com/repos/${owner}/${repo}/commits`,
1446				{
1447					headers: {
1448						Authorization: `token ${token}`,
1449						Accept: 'application/vnd.github+json',
1450						'X-GitHub-Api-Version': '2022-11-28',
1451					},
1452					params: { per_page: perPage, page },
1453				},
1454			);
1455	
1456			if (commits.length === 0) break;
1457	
1458			await this.commitModel.upsertMany({
1459				commits: commits.map((c) => ({
1460					installation_id: installationDbId,
1461					repo_id: repoDbId,
1462					sha: c.sha,
1463					message: c.commit.message,
1464					author_login: c.author?.login ?? null,
1465					author_name: c.commit.author.name,
1466					author_email: c.commit.author.email,
1467					committed_at: new Date(c.commit.author.date),
1468					additions: c.stats?.additions ?? 0,
1469					deletions: c.stats?.deletions ?? 0,
1470					is_merge_commit: c.parents.length > 1,
1471				})),
1472			});
1473	
1474			if (commits.length < perPage) break;
1475			page++;
1476		}
1477	
1478		this.logger.debug(`Backfilled commits for ${repoFullName}`);
1479	}
