1481	private async backfillPullRequests({
1482		installationDbId,
1483		repoDbId,
1484		repoFullName,
1485		owner,
1486		repo,
1487		token,
1488	}: {
1489		installationDbId: string;
1490		repoDbId: string;
1491		repoFullName: string;
1492		owner: string;
1493		repo: string;
1494		token: string;
1495	}): Promise<void> {
1496		let page = 1;
1497		const perPage = 100;
1498	
1499		while (true) {
1500			const { data: prs } = await this.httpService.axiosRef.get<IGithubApiPullRequest[]>(
1501				`https://api.github.com/repos/${owner}/${repo}/pulls`,
1502				{
1503					headers: {
1504						Authorization: `token ${token}`,
1505						Accept: 'application/vnd.github+json',
1506						'X-GitHub-Api-Version': '2022-11-28',
1507					},
1508					params: { state: 'all', per_page: perPage, page },
1509				},
1510			);
1511	
1512			if (prs.length === 0) break;
1513	
1514			for (const pr of prs) {
1515				await this.contributorModel.upsert({
1516					data: {
1517						installation_id: installationDbId,
1518						github_user_id: pr.user.id,
1519						github_login: pr.user.login,
1520					},
1521				});
1522	
1523				const saved = await this.pullRequestModel.upsert({
1524					data: {
1525						installation_id: installationDbId,
1526						repo_id: repoDbId,
1527						github_pr_id: pr.id,
1528						pr_number: pr.number,
1529						title: pr.title,
1530						state: pr.state as GithubPRState,
1531						author_login: pr.user.login,
1532						draft: pr.draft,
1533						merged: pr.merged,
1534						additions: pr.additions,
1535						deletions: pr.deletions,
1536						changed_files: pr.changed_files,
1537						commits_count: pr.commits,
1538						opened_at: new Date(pr.created_at),
1539						merged_at: pr.merged_at ? new Date(pr.merged_at) : null,
1540						closed_at: pr.closed_at ? new Date(pr.closed_at) : null,
1541					},
1542				});
1543	
1544				await this.backfillReviews({ installationDbId, prDbId: saved._id, owner, repo, prNumber: pr.number, token });
1545				await this.backfillReviewComments({ installationDbId, prDbId: saved._id, owner, repo, prNumber: pr.number, token });
1546			}
1547	
1548			if (prs.length < perPage) break;
1549			page++;
1550		}
1551	
1552		this.logger.debug(`Backfilled PRs for ${repoFullName}`);
1553	}
