1555	private async backfillReviews({
1556		installationDbId,
1557		prDbId,
1558		owner,
1559		repo,
1560		prNumber,
1561		token,
1562	}: {
1563		installationDbId: string;
1564		prDbId: string;
1565		owner: string;
1566		repo: string;
1567		prNumber: number;
1568		token: string;
1569	}): Promise<void> {
1570		const { data: reviews } = await this.httpService.axiosRef.get<IGithubApiReview[]>(
1571			`https://api.github.com/repos/${owner}/${repo}/pulls/${prNumber}/reviews`,
1572			{
1573				headers: {
1574					Authorization: `token ${token}`,
1575					Accept: 'application/vnd.github+json',
1576					'X-GitHub-Api-Version': '2022-11-28',
1577				},
1578				params: { per_page: 100 },
1579			},
1580		);
1581	
1582		for (const review of reviews) {
1583			const normalizedState = review.state.toLowerCase();
1584			const validStates = ['approved', 'changes_requested', 'commented', 'dismissed'];
1585			if (!validStates.includes(normalizedState)) continue;
1586	
1587			await this.contributorModel.upsert({
1588				data: {
1589					installation_id: installationDbId,
1590					github_user_id: review.user.id,
1591					github_login: review.user.login,
1592				},
1593			});
1594	
1595			await this.reviewModel.upsert({
1596				data: {
1597					installation_id: installationDbId,
1598					pull_request_id: prDbId,
1599					github_review_id: review.id,
1600					reviewer_login: review.user.login,
1601					state: normalizedState as GithubReviewState,
1602					submitted_at: new Date(review.submitted_at),
1603				},
1604			});
1605		}
1606	}
